const contentful = require('contentful')


const client = contentful.createClient({
  space: 'kr6ve4el3apk',
  accessToken: '7b40c1aeea2b09e1904892c228e1b7e4f0c3df4ab2163509d527cc6f1e9b0f1a'
});


exports.getAllCourses = () => client.getEntries({content_type: 'courses'})
		.then(response => response.items.map((x) => x.fields))
		.catch(err => { console.log(err) })

exports.getCourseBySlug = slug => client.getEntries({content_type: 'courses','fields.slug': `${slug}`})
      	.then(response => response.items.map(x => x.fields).find(course => course.slug === slug ))
      	.catch(err => { console.log(err) })



