import { combineReducers } from "redux";
import { firestoreReducer } from "redux-firestore";
import { firebaseReducer } from "react-redux-firebase";
import { reducer as reduxFormReducer } from "redux-form";
// import { validate } from "../pages/createCourse";
const authReducer = (state = { isAuth: false, authError: null }, action) => {
	switch (action.type) {
		case "LOGIN_SUCESSFUL":
			console.log("Auth login");
			return {
				...state,
				authError: null
			};
		case "LOGIN_ERROR":
			return {
				...state,
				authError: action.payload.message
			};
		case "SIGNUP_SUCESSFUL":
			console.log("Auth signed up");
			return {
				...state,
				authError: null
			};
		case "SIGNUP_ERROR":
			return {
				...state,
				authError: action.payload.message
			};
		case "LOGOUT_SUCESSFUL":
			console.log("Auth logged out");
			return {
				...state,
				authError: null
			};
		case "LOGOUT_ERROR":
			return {
				...state,
				authError: "Logged out failed"
			};
		default:
			return state;
	}
};

const courseReducer = (state = {}, action) => {
	switch (action.type) {
		case "GET_COURSES":
			return {
				...state,
				...action.payload
			};

		default:
			return state;
	}
};

const rootReducer = combineReducers({
	auth: authReducer,
	course: courseReducer,
	firestore: firestoreReducer,
	firebase: firebaseReducer,
	form: reduxFormReducer
});

export default rootReducer;
