export const signIn = data => {
	return (dispatch, getState, { getFirebase, getFirestore }) => {
		const firebase = getFirebase();
		console.log(data);
		firebase
			.auth()
			.signInWithEmailAndPassword(data.email, data.password)
			.then(() => dispatch({ type: "LOGIN_SUCESSFUL" }))
			.catch(err => dispatch({ type: "LOGIN_ERROR", payload: err }));
	};
};

export const signUp = data => {
	return (dispatch, getState, { getFirebase, getFirestore }) => {
		const firebase = getFirebase();
		const firestore = getFirestore();
		console.log(data);
		firebase
			.auth()
			.createUserWithEmailAndPassword(data.email, data.password)
			.then(response => {
				firestore
					.collection("users")
					.doc(response.user.uid)
					.set({
						displayName: data.fullname,
						photoURL: "http://react.semantic-ui.com/images/avatar/small/elliot.jpg",
						email: data.email
					});
			})
			.then(() => dispatch({ type: "SIGNUP_SUCESSFUL" }) )
			.catch(err => dispatch({ type: "SIGNUP_ERROR", payload: err }));
	};
};

export const logOut = () => {
	return (dispatch, getState, { getFirebase, getFirestore }) => {
		const firebase = getFirebase();
		firebase
			.auth()
			.signOut()
			.then(() => dispatch({ type: "LOGOUT_SUCESSFUL" }))
			.catch(err => dispatch({ type: "LOGOUT_ERROR", payload: err }));
	};
};

