import React from "react";
import { NavLink, Link } from "react-router-dom";
import { Menu, Image, Dropdown, Container, Header } from "semantic-ui-react";
// import Login from "./Login";
// import Signup from "./Signup";
import { connect } from "react-redux";
import { logOut } from "../store/authActions";
// import SearchBarHooks from "./SearchBarHooks";
import SearchBar from "./SearchBar";

function Navbar(props) {
    const { auth, profile, logOut } = props;
    return (
        <Menu fixed="top" borderless style={{ zIndex: "1000" }}>
            <Container>
                <Menu.Item header as={Link} to="/">
                    <Image
                        size="mini"
                        src="https://react.semantic-ui.com/logo.png"
                        style={{ marginRight: "1.5em" }}
                    />
                    Project Name
                </Menu.Item>
                <Menu.Item as={NavLink} to="/" exact>
                    Home
                </Menu.Item>

                <Menu.Item>
                    <SearchBar />
                </Menu.Item>
                <Menu.Menu position="right">
                    {auth.uid ? (
                        <Dropdown
                            direction="left"
                            item
                            simple
                            trigger={
                                <React.Fragment>
                                    <Image
                                        size="mini"
                                        style={{ marginLeft: "1.5em" }}
                                        src={profile.photoURL}
                                        avatar
                                    />
                                </React.Fragment>
                            }
                        >

                            <Dropdown.Menu>
                                <Dropdown.Item
                                    as={Link}
                                    to="/"
                                    content={
                                        <Header as='h6'
                                            image={profile.photoURL}
                                            content={profile.displayName}
                                            subheader={profile.email}

                                        />
                                    }
                                />
                                <Dropdown.Item as={Link} to="/">
                                    Settings
                                </Dropdown.Item>
                                <Dropdown.Divider />
                                <Dropdown.Header as={Link} to="/">
                                    Privacy
                                </Dropdown.Header>
                                <Dropdown.Item
                                    as={Link}
                                    to="/"
                                    onClick={logOut}
                                >
                                    Log Out
                                </Dropdown.Item>
                            </Dropdown.Menu>
                        </Dropdown>
                    ) : (
                        <React.Fragment>
                            <Menu.Item as={NavLink} to="/login">
                                Log In
                            </Menu.Item>
                            <Menu.Item as={NavLink} to="/signup">
                                Sign Up
                            </Menu.Item>
                        </React.Fragment>
                    )}
                </Menu.Menu>
            </Container>
        </Menu>
    );
}

const mapStateToProps = state => {
    console.log(state);
    return {
        auth: state.firebase.auth,
        profile: state.firebase.profile
    };
};

const mapDispatchToProps = dispatch => {
    return {
        logOut: () => dispatch(logOut())
    };
};

export default connect(
    mapStateToProps,
    mapDispatchToProps
)(Navbar);

